use std "cobject/cterminal.obs";

fn main() {
    #terminal = new_cterminal();

    #@char = '\0';

    £ char != '1' 
    {
        char = get_pressed_key();

        ? char != '\0' {
            set_char(&terminal, 10, 10, char);
        };

        show(&terminal);
    };
};
